sql:
SELECT user_id, COUNT(interaction_id) AS Total_Interactions
FROM user_track_interactions
GROUP BY user_id;

external_knowledge:
- Admirers in this context are synonymous with followers;
- Musical seeds refer to the tracks or songs released by the artists;
- Heartful acknowledgments symbolize likes that the tracks have received;
- Artists sailing in the middle waters of popularity are those with a follower count between 10,000 and 500,000.

sql:
SELECT AVG(track_count) 
FROM (
  SELECT COUNT(track_id) AS track_count 
  FROM user_track_interactions 
  GROUP BY user_id
) AS user_track_counts;

SELECT playlist_id, COUNT(track_id) AS track_count
FROM playlist_tracks
GROUP BY playlist_id;

SELECT COUNT(DISTINCT user_id)
FROM user_track_interactions
WHERE track_id = 'input_track_id';

SELECT track_name, artist_id, album 
FROM music_tracks
ORDER BY artist_id ASC;

external_knowledge:
- 'more popular artists' refers to those with a higher number of followers;
- 'typical grooviness' means the average danceability of the tracks;
- 'particularly dance-inducing tracks' indicates tracks with a danceability score greater than 0.7.

sql:
SELECT track_name
FROM music_tracks
WHERE danceability > 0.8 AND energy > 0.8;

external_knowledge:
- 'popular artists' refers to artists with a popularity score greater than 0.5; 
- 'significant fan base' means they have more than 10,000 followers; 
- 'multiple songs' indicates at least 6 tracks; 
- 'public playlists' refers to playlists with 'public' visibility; 
- 'user engagements' cover all types of user interactions with the artist's tracks.

- 'very well-known' implies high popularity scores;
- 'great for dancing' refers to high average danceability;
- 'top ten' indicates a limit of 10 results;
- 'sorted from the most popular and most danceable first' means ordering by popularity and then by danceability in descending order.

sql:
SELECT user_id, AVG(interaction_id) AS avg_interactions 
FROM user_track_interactions 
GROUP BY user_id;

external_knowledge:
- "musical maestros" refers to artists;
- "catching the rhythmic winds" and "harnessing the vibrant spirit" are metaphors for high danceability and energy in music;
- "stir the most hearts and feet" metaphorically represents high popularity and user engagement;
- "waves of user engagement" is a metaphor for the number of interactions users have with an artist's music.

sql:
SELECT artist_id, name
FROM artists
WHERE followers > (SELECT AVG(followers) FROM artists);
